import{_ as e,c as t,o as d,ae as i}from"./chunks/framework.CkyPvWOg.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"css/百分号.md","filePath":"css/百分号.md","lastUpdated":1773308029000}'),a={name:"css/百分号.md"};function r(n,o,c,l,s,g){return d(),t("div",null,[...o[0]||(o[0]=[i('<h3 id="一。包含块" tabindex="-1">一。包含块 <a class="header-anchor" href="#一。包含块" aria-label="Permalink to &quot;一。包含块&quot;">​</a></h3><p><strong>包含块的确定规则</strong></p><ol><li><code>position: static或relative</code>: 包含块是<strong>最近的块级祖先元素的内容区域(<code>width</code>)(<code>content box</code>)</strong>。如果没有块级祖先，则默认为根元素</li><li><code>position: absolute</code>: 包含块是其最近的<code>position</code>值不为<code>static</code>的祖先元素的<strong>内边距边界(<code>padding</code>)</strong>。如果没有这样的祖先元素，则包含块是根元素</li><li><code>position: fixed</code>‌： 包含块是<strong>视口</strong></li><li><strong>普通元素：</strong> 包含块是<strong>最近的块级祖先元素的内容区域(<code>width</code>)(<code>content box</code>)</strong></li></ol><h3 id="一。-百分比的参考系-包含块" tabindex="-1">一。 百分比的参考系(包含块) <a class="header-anchor" href="#一。-百分比的参考系-包含块" aria-label="Permalink to &quot;一。 百分比的参考系(包含块)&quot;">​</a></h3><h4 id="百分比的值始终相对于其元素的包含块‌-containing-block-‌" tabindex="-1">百分比的值始终相对于其元素的包含块‌（Containing Block）‌ <a class="header-anchor" href="#百分比的值始终相对于其元素的包含块‌-containing-block-‌" aria-label="Permalink to &quot;百分比的值始终相对于其元素的包含块‌（Containing Block）‌&quot;">​</a></h4><h4 id="绝对定位元素的百分比-相对于包含块的内边距区域-padding-计算" tabindex="-1">绝对定位元素的百分比： 相对于包含块的<strong>内边距区域</strong>(<code>padding</code>)计算 <a class="header-anchor" href="#绝对定位元素的百分比-相对于包含块的内边距区域-padding-计算" aria-label="Permalink to &quot;绝对定位元素的百分比： 相对于包含块的&lt;strong&gt;内边距区域&lt;/strong&gt;(`padding`)计算&quot;">​</a></h4><ol><li><strong>普通元素</strong>：参考系为父元素的内容区域（content box）‌</li><li><strong>绝对定位</strong>: 参考系为最近定位祖先元素的<code>padding</code><strong>(内边距)</strong>区域.即父级元素设置了position: relative/absolute/fixed）‌</li></ol><ul><li><code>position: static</code> （静态定位）或 <code>position: relative</code>（相对定位）: 参考系通常是由它最近的块级、表格单元格或行内块祖先元素的<code>内容区域（content box）</code>确定</li><li><code>position: absolute</code>（绝对定位）： 其参考系由最近的、position值不为static（即relative、absolute或fixed）的祖先元素的<strong>内边距区域</strong>(<code>padding</code>)确定</li><li><code>position: fixed</code>（固定定位）：相对于浏览器窗口进行定位</li></ul><h3 id="二。-常见属性的百分比计算规则" tabindex="-1">二。 常见属性的百分比计算规则 <a class="header-anchor" href="#二。-常见属性的百分比计算规则" aria-label="Permalink to &quot;二。 常见属性的百分比计算规则&quot;">​</a></h3><div style="background-color:red;color:#fff;">绝对定位元素的百分比： 相对于包含块的<strong>内边距区域</strong>(`padding`)计算</div><ol><li><code>width</code> 和 <code>height</code></li></ol><ul><li><code>width</code>：百分比相对于参考系的宽度‌(<code>wdith</code>)<strong>(content box 内容区域)</strong><ul><li>示例：父元素宽600px，子元素设置<code>width: 50%</code>，则实际宽度为300px‌</li></ul></li><li><code>height</code>：百分比相对于参考系的高度‌(<code>height</code>)<strong>(content box 内容区域)</strong><ul><li>陷阱：若父元素高度未显式定义（如<code>height: auto</code>），子元素的<code>height: 100%</code>可能失效‌</li></ul></li></ul><ol start="2"><li><code>padding</code>、<code>margin</code>、<code>border</code></li></ol><div style="background-color:red;color:#fff;">绝对定位元素的百分比： 相对于包含块的<strong>内边距区域</strong>(`padding`)计算</div><ul><li>百分比均相对于参考系的‌<strong>宽度‌(width)</strong>计算‌</li></ul><h3 id="三。-top、bottom、left、right" tabindex="-1">三。 <code>top</code>、<code>bottom</code>、<code>left</code>、<code>right</code> <a class="header-anchor" href="#三。-top、bottom、left、right" aria-label="Permalink to &quot;三。 `top`、`bottom`、`left`、`right`&quot;">​</a></h3><div style="background-color:red;color:#fff;">绝对定位元素的百分比： 相对于包含块的<strong>内边距区域</strong>(`padding`)计算</div><ul><li><code>left</code>/<code>right</code>: 相对于参考系的<strong>宽度<code>(width)</code></strong></li><li><code>top</code>/<code>bottom</code>： 相对于参考系的<strong>高度<code>(height)</code></strong></li></ul><h3 id="四。font-size" tabindex="-1">四。<code>font-size</code> <a class="header-anchor" href="#四。font-size" aria-label="Permalink to &quot;四。`font-size`&quot;">​</a></h3><ul><li>相对于<strong>父元素的字体大小‌</strong></li></ul><h3 id="五。border-radius-的百分比" tabindex="-1">五。<code>border-radius</code> 的百分比 <a class="header-anchor" href="#五。border-radius-的百分比" aria-label="Permalink to &quot;五。`border-radius` 的百分比&quot;">​</a></h3><ul><li>相对于<strong>父元素</strong>的<code>width</code>和<code>height</code>。分别计算水平和垂直半径‌</li></ul><h3 id="六。line-height" tabindex="-1">六。<code>line-height</code> <a class="header-anchor" href="#六。line-height" aria-label="Permalink to &quot;六。`line-height`&quot;">​</a></h3><ul><li>相对于<strong>自身</strong>的<code>font-size</code>值‌</li></ul><h3 id="七。-transform-中的百分比" tabindex="-1">七。 <code>transform</code> 中的百分比 <a class="header-anchor" href="#七。-transform-中的百分比" aria-label="Permalink to &quot;七。 `transform` 中的百分比&quot;">​</a></h3><ul><li><code>translateX(50%)</code>：相对于<strong>自身宽度</strong>的一半‌</li><li><code>translateY(50%)</code>：相对于<strong>自身高度</strong>的一半‌</li></ul>',26)])])}const b=e(a,[["render",r]]);export{u as __pageData,b as default};
